import React, { useEffect, useMemo, useState } from "react";
import {
  MapContainer,
  TileLayer,
  Marker,
  Popup,
  ScaleControl,
  useMap,
} from "react-leaflet";
import MarkerClusterGroup from "react-leaflet-cluster";
import L from "leaflet";
import { useI18n } from "@/framework/i18n/hooks";
import "leaflet/dist/leaflet.css";
import "leaflet.markercluster/dist/MarkerCluster.css";
import "leaflet.markercluster/dist/MarkerCluster.Default.css";

// Fix default icon paths
delete (L.Icon.Default.prototype as any)._getIconUrl;
L.Icon.Default.mergeOptions({
  iconRetinaUrl:
    "https://unpkg.com/leaflet@1.9.4/dist/images/marker-icon-2x.png",
  iconUrl: "https://unpkg.com/leaflet@1.9.4/dist/images/marker-icon.png",
  shadowUrl: "https://unpkg.com/leaflet@1.9.4/dist/images/marker-shadow.png",
});

type User = { id: string; name: string; lat: number; lng: number };

type UserStatus = "normal" | "alert" | "critical";

type PopupUser = User & {
  age?: number;
  location?: string;
  lastSeen?: string;
  battery?: string;
  status?: UserStatus;
};

function formatLastSeen(formatter: Intl.DateTimeFormat, value?: string) {
  if (!value) return "-";
  return formatter.format(new Date(value));
}

function getStatusLabel(
  status: UserStatus | undefined,
  t: (key: string, options?: any) => string,
) {
  if (status === "critical") return t("map.statusCritical");
  if (status === "alert") return t("map.statusAlert");
  return t("map.statusNormal");
}

type PopupLabels = {
  id: string;
  age: string;
  ageUnit: (count: number | string) => string;
  location: string;
  status: string;
  battery: string;
  updated: string;
  statusLabel: (status?: UserStatus) => string;
  formatLastSeen: (value?: string) => string;
};

function buildPopupHtml(user: PopupUser, labels: PopupLabels) {
  return `
    <div style="min-width:180px;padding:2px 0;line-height:1.45;color:#1f2937;">
      <div style="font-size:22px;font-weight:800;margin-bottom:2px;">${
        user.name
      }</div>
      <div style="font-size:12px;color:#6b7280;margin-bottom:8px;">${
        labels.id
      }: ${user.id}</div>
      <div style="display:grid;grid-template-columns:64px 1fr;gap:4px 8px;font-size:13px;">
        <div style="color:#6b7280;">${
          labels.age
        }</div><div style="font-weight:600;">${
    user.age != null ? labels.ageUnit(user.age) : "-"
  }</div>
        <div style="color:#6b7280;">${
          labels.location
        }</div><div style="font-weight:600;">${user.location ?? "-"}</div>
        <div style="color:#6b7280;">${
          labels.status
        }</div><div style="font-weight:600;">${labels.statusLabel(
    user.status,
  )}</div>
        <div style="color:#6b7280;">${
          labels.battery
        }</div><div style="font-weight:600;">${user.battery ?? "-"}</div>
        <div style="color:#6b7280;">${
          labels.updated
        }</div><div style="font-weight:600;">${labels.formatLastSeen(
    user.lastSeen,
  )}</div>
      </div>
    </div>
  `;
}

function PopupContent({
  user,
  labels,
}: {
  user: PopupUser;
  labels: PopupLabels;
}) {
  return (
    <div style={{ minWidth: 180, padding: "2px 0", lineHeight: 1.45 }}>
      <div style={{ fontSize: 22, fontWeight: 800, marginBottom: 2 }}>
        {user.name}
      </div>
      <div style={{ fontSize: 12, color: "#6b7280", marginBottom: 8 }}>
        {labels.id}: {user.id}
      </div>
      <div
        style={{
          display: "grid",
          gridTemplateColumns: "64px 1fr",
          gap: "4px 8px",
          fontSize: 13,
          color: "#1f2937",
        }}
      >
        <div style={{ color: "#6b7280" }}>{labels.age}</div>
        <div style={{ fontWeight: 600 }}>
          {user.age != null ? labels.ageUnit(user.age) : "-"}
        </div>
        <div style={{ color: "#6b7280" }}>{labels.location}</div>
        <div style={{ fontWeight: 600 }}>{user.location ?? "-"}</div>
        <div style={{ color: "#6b7280" }}>{labels.status}</div>
        <div style={{ fontWeight: 600 }}>{labels.statusLabel(user.status)}</div>
        <div style={{ color: "#6b7280" }}>{labels.battery}</div>
        <div style={{ fontWeight: 600 }}>{user.battery ?? "-"}</div>
        <div style={{ color: "#6b7280" }}>{labels.updated}</div>
        <div style={{ fontWeight: 600 }}>
          {labels.formatLastSeen(user.lastSeen)}
        </div>
      </div>
    </div>
  );
}

const FitBounds: React.FC<{ users: User[] }> = ({ users }) => {
  const map = useMap();
  useEffect(() => {
    if (!map) return;
    if (!users || users.length === 0) return;
    const bounds = L.latLngBounds(
      users.map((u) => [u.lat, u.lng] as [number, number]),
    );
    map.fitBounds(bounds, { padding: [40, 40] });
  }, [map, users]);
  return null;
};

const SelectedUserEffect: React.FC<{
  users: PopupUser[];
  selectedUserId?: string;
}> = ({ users, selectedUserId }) => {
  const map = useMap();
  const { t, i18n } = useI18n(["dashboard"]);
  const popupDateFormatter = useMemo(
    () =>
      new Intl.DateTimeFormat(i18n.language === "en" ? "en-US" : "ko-KR", {
        month: "2-digit",
        day: "2-digit",
        hour: "2-digit",
        minute: "2-digit",
        hour12: false,
      }),
    [i18n.language],
  );
  const popupLabels = useMemo<PopupLabels>(
    () => ({
      id: t("map.id"),
      age: t("map.age"),
      ageUnit: (count) => t("map.ageUnit", { count }),
      location: t("map.location"),
      status: t("map.status"),
      battery: t("map.battery"),
      updated: t("map.updated"),
      statusLabel: (status) => getStatusLabel(status, t),
      formatLastSeen: (value) => formatLastSeen(popupDateFormatter, value),
    }),
    [popupDateFormatter, t],
  );

  useEffect(() => {
    if (!map) return;
    if (!selectedUserId) return;
    const u = users.find((x) => x.id === selectedUserId);
    if (!u) return;
    const latlng: [number, number] = [u.lat, u.lng];
    map.setView(latlng, 15, { animate: true });
    L.popup({ maxWidth: 320 })
      .setLatLng(latlng)
      .setContent(buildPopupHtml(u, popupLabels))
      .openOn(map);
  }, [map, popupLabels, selectedUserId, users]);
  return null;
};

const RegionEffect: React.FC<{
  regionCenter?: { lat: number; lng: number } | null;
}> = ({ regionCenter }) => {
  const map = useMap();
  useEffect(() => {
    if (!map) return;
    if (!regionCenter) return;
    map.setView([regionCenter.lat, regionCenter.lng], 12, { animate: true });
  }, [map, regionCenter]);
  return null;
};

const OSMMap: React.FC<{
  users?: PopupUser[];
  selectedUserId?: string;
  regionCenter?: { lat: number; lng: number } | null;
}> = ({ users = [], selectedUserId, regionCenter = null }) => {
  const { t } = useI18n(["dashboard"]);
  const [base, setBase] = useState<"osm" | "sat">("osm");

  const popupDateFormatter = useMemo(
    () =>
      new Intl.DateTimeFormat(t("map.viewMap") === "Map" ? "en-US" : "ko-KR", {
        month: "2-digit",
        day: "2-digit",
        hour: "2-digit",
        minute: "2-digit",
        hour12: false,
      }),
    [t],
  );

  const popupLabels = useMemo<PopupLabels>(
    () => ({
      id: t("map.id"),
      age: t("map.age"),
      ageUnit: (count) => t("map.ageUnit", { count }),
      location: t("map.location"),
      status: t("map.status"),
      battery: t("map.battery"),
      updated: t("map.updated"),
      statusLabel: (status) => getStatusLabel(status, t),
      formatLastSeen: (value) => formatLastSeen(popupDateFormatter, value),
    }),
    [popupDateFormatter, t],
  );

  const center: [number, number] = users.length
    ? [users[0].lat, users[0].lng]
    : [35.1796, 129.0756];

  const tileLayer = useMemo(() => {
    if (base === "osm") {
      return {
        url: "https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png",
        attribution:
          '&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a>',
      };
    }
    // Use Esri World Imagery for satellite as a permissive option
    return {
      url: "https://server.arcgisonline.com/ArcGIS/rest/services/World_Imagery/MapServer/tile/{z}/{y}/{x}",
      attribution:
        "Tiles &copy; Esri &mdash; Source: Esri, Maxar, Earthstar Geographics",
    };
  }, [base]);

  return (
    <div style={{ height: "100%", width: "100%", position: "relative" }}>
      <div style={{ position: "absolute", top: 8, right: 8, zIndex: 400 }}>
        <div style={{ display: "flex", gap: 8 }}>
          <button
            onClick={() => setBase("osm")}
            style={{ padding: "6px 8px", borderRadius: 4, cursor: "pointer" }}
          >
            {t("map.viewMap")}
          </button>
          <button
            onClick={() => setBase("sat")}
            style={{ padding: "6px 8px", borderRadius: 4, cursor: "pointer" }}
          >
            {t("map.viewSatellite")}
          </button>
        </div>
      </div>

      <MapContainer
        center={center}
        zoom={13}
        style={{ height: "100%", width: "100%" }}
      >
        <TileLayer url={tileLayer.url} attribution={tileLayer.attribution} />
        <ScaleControl position="bottomleft" />
        <FitBounds users={users} />
        <RegionEffect regionCenter={regionCenter} />
        <SelectedUserEffect users={users} selectedUserId={selectedUserId} />
        <MarkerClusterGroup chunkedLoading>
          {users.map((u) => (
            <Marker key={u.id} position={[u.lat, u.lng]}>
              <Popup minWidth={220} maxWidth={320}>
                <PopupContent user={u} labels={popupLabels} />
              </Popup>
            </Marker>
          ))}
        </MarkerClusterGroup>
      </MapContainer>
    </div>
  );
};

export default OSMMap;
