  const bannerTimeFontSize = isMobile ? 18 : 24;
  const bannerOrgFontSize = isMobile ? 20 : 28;
  const regionHeadlineFontSize = isMobile ? 18 : 26;
  const metaFontSize = isMobile ? 11 : 13;
  const metricLabelFontSize = isMobile ? 11 : 13;
  const metricValueFontSize = isMobile ? 28 : isTablet ? 34 : 44;
  const metricSubValueFontSize = isMobile ? 30 : 40;
