  const detailValueFontSize = isMobile ? 22 : 26;
  const detailMetaFontSize = isMobile ? 10 : 11;
  const trendLegendFontSize = isMobile ? 9 : 10;
  const trendAxisFontSize = isMobile ? 9 : 10;
