const now = new Date("2026-04-07T15:25:28+09:00");

function buildUsers(): UserRecord[] {
  const users: UserRecord[] = [];
  let idx = 0;

  REGIONS.forEach((region, regionIndex) => {
    for (let count = 0; count < region.userCount; count += 1) {
      const age = AGE_PATTERN[(idx + regionIndex) % AGE_PATTERN.length];
      const lastSeen = new Date(now.getTime() - idx * 1000 * 60 * 17);
      users.push({
        idx: idx + 1,
        id: `busan-user-${idx + 1}`,
        name: NAME_POOL[idx % NAME_POOL.length],
        Fb: `busan-user-${idx + 1}`,
        age,
        location: region.name,
        lat: region.center.lat + ((count % 3) - 1) * 0.008,
        lng:
          region.center.lng +
          ((count % 2 === 0 ? 1 : -1) * 0.01 + regionIndex * 0.0004),
        lastSeen: lastSeen.toISOString(),
        status:
          age >= 65
            ? "critical"
            : age <= 13 || idx % 7 === 0
            ? "alert"
            : "normal",
        battery: `${58 + ((idx * 7) % 35)}%`,
      });
      idx += 1;
    }
  });

  return users;
}

const USERS = buildUsers();
const TOTAL_USERS = USERS.length;
const AGE_BREAKDOWN = USERS.reduce(
  (acc, user) => {
    if (user.age >= 65) {
      acc.senior += 1;
    } else if (user.age <= 13) {
      acc.child += 1;
    } else {
      acc.adult += 1;
    }
    return acc;
  },
  { senior: 0, adult: 0, child: 0 },
);

const AGE_RATIO = {
  senior: Math.round((AGE_BREAKDOWN.senior / TOTAL_USERS) * 100),
  adult: Math.round((AGE_BREAKDOWN.adult / TOTAL_USERS) * 100),
  child: Math.round((AGE_BREAKDOWN.child / TOTAL_USERS) * 100),
};

const HISTORY_STEPS: Record<HistoryPeriod, number> = {
  week: 24 * 60 * 60 * 1000,
  day: 60 * 60 * 1000,
  hour: 60 * 1000,
};

function getHistorySeries(period: HistoryPeriod = "week") {
  if (period === "week") {
    const term = Array.from({ length: 7 }).map((_, index) => {
      const date = new Date(now);
      date.setDate(now.getDate() - (6 - index));
      return date.toISOString().slice(0, 10);
    });
    return { term, counts: WEEK_COUNTS };
  }

  if (period === "day") {
    const term = Array.from({ length: 24 }).map(
      (_, index) => `${String(index).padStart(2, "0")}:00`,
    );
    return { term, counts: DAY_COUNTS };
  }

  const term = Array.from({ length: 60 }).map(
    (_, index) => `${String(index).padStart(2, "0")}분`,
  );
  return { term, counts: HOUR_COUNTS };
}

function buildSnapshot(snapshot?: HistorySnapshot) {
  const period = snapshot?.period ?? "week";
  const { term, counts } = getHistorySeries(period);
  const safeOffset = Math.min(
    Math.max(snapshot?.offset ?? 0, 0),
    Math.max(counts.length - 1, 0),
  );
  const targetIndex = Math.max(counts.length - 1 - safeOffset, 0);
  const targetCount = counts[targetIndex] ?? TOTAL_USERS;
  const targetTime = new Date(
    now.getTime() - safeOffset * HISTORY_STEPS[period],
  );
  const rotation = safeOffset % USERS.length;
  const rotatedUsers = USERS.slice(rotation).concat(USERS.slice(0, rotation));
  const visibleUsers = rotatedUsers.slice(0, targetCount).map((user, index) => {
    const minutesAgo = (index % 6) * 7 + Math.floor(index / 6) * 3;
    const batteryBase = Number(user.battery.replace("%", ""));

    return {
      ...user,
      idx: index + 1,
      lastSeen: new Date(
        targetTime.getTime() - minutesAgo * 60 * 1000,
      ).toISOString(),
      battery: `${Math.max(
        18,
        Math.min(100, batteryBase - safeOffset + (index % 4)),
      )}%`,
      status:
        safeOffset === 0
          ? user.status
          : user.age >= 65
          ? "critical"
          : index % 8 === 0 || user.age <= 13
          ? "alert"
          : "normal",
    };
  });

  const ageBreakdown = visibleUsers.reduce(
    (acc, user) => {
      if (user.age >= 65) {
        acc.senior += 1;
      } else if (user.age <= 13) {
        acc.child += 1;
      } else {
        acc.adult += 1;
      }
      return acc;
    },
    { senior: 0, adult: 0, child: 0 },
  );

  const ageRatio = {
    senior: visibleUsers.length
      ? Math.round((ageBreakdown.senior / visibleUsers.length) * 100)
      : 0,
    adult: visibleUsers.length
      ? Math.round((ageBreakdown.adult / visibleUsers.length) * 100)
      : 0,
    child: visibleUsers.length
      ? Math.round((ageBreakdown.child / visibleUsers.length) * 100)
      : 0,
  };

  const byType = {
    normal: visibleUsers.filter((user) => user.status === "normal").length,
    alert: visibleUsers.filter((user) => user.status === "alert").length,
    critical: visibleUsers.filter((user) => user.status === "critical").length,
  };

  const regionValues = REGIONS.map((region) => {
    const usersInRegion = visibleUsers.filter(
      (user) => user.location === region.name,
    );
    return {
      id: region.id,
      name: region.name,
      value: usersInRegion.length,
      center: region.center,
    };
  });

  return {
    term,
    counts,
    targetIndex,
    targetTime,
    users: visibleUsers,
    ageBreakdown,
    ageRatio,
    byType,
    regions: regionValues,
  };
}

export async function getDisasterAlert(
  snapshot?: HistorySnapshot,
): Promise<any> {
  const { targetTime } = buildSnapshot(snapshot);
  return Promise.resolve({
    list: [
      {
        id: "busan-alert-1",
        title: "부산 전역 강풍 예비특보 발효",
        idx: 0,
        severity: "warning",
        time: targetTime.toISOString(),
      },
      {
        id: "busan-alert-2",
        title: "해운대구 해안가 침수 주의",
        idx: 1,
        severity: "info",
        time: new Date(targetTime.getTime() - 1000 * 60 * 35).toISOString(),
      },
    ],
  });
}

export async function getUserClassification(
  snapshot?: HistorySnapshot,
): Promise<any> {
  const { users, byType, ageBreakdown, ageRatio, targetTime } =
    buildSnapshot(snapshot);

  return Promise.resolve({
    locNm: "부산광역시",
    total: users.length,
    byType,
    ageBreakdown,
    ageRatio,
    updatedAt: targetTime.toISOString(),
  });
}

export async function getUserList(snapshot?: HistorySnapshot): Promise<any> {
  const { users } = buildSnapshot(snapshot);

  return Promise.resolve({
    list: users,
    total: users.length,
    page: 1,
    pageSize: users.length,
  });
}

export async function getUserHistory(
  period: HistoryPeriod = "week",
): Promise<any> {
  return Promise.resolve(getHistorySeries(period));
}

export async function getUserLocationStatus(
  snapshot?: HistorySnapshot,
): Promise<any> {
  return Promise.resolve(buildSnapshot(snapshot).regions);
}

export default {
  getDisasterAlert,
  getUserClassification,
  getUserList,
  getUserHistory,
  getUserLocationStatus,
  BUSAN_CENTER,
};
